  extractGitHubLinks,
  checkGitHubRepo,
  validateAllLinks
}

// Run if executed directly
/* c8 ignore start */
if (require.main === module) {
  validateAllLinks()
    .then(({ notFound }) => {
      if (notFound.length > 0) {
        process.exit(1)
      }
    })
    .catch((err) => {
      console.error(err)
      process.exit(1)
    })
}
/* c8 ignore stop */

