fn test_run_summary_enable_matrix() {
    let tempdir = tempfile::tempdir().unwrap();
    setup::setup_integration_test(tempdir.path(), "basic_monorepo", "npm@10.5.0", true).unwrap();

    struct Case {
        env_val: Option<&'static str>,
        flag: Option<&'static str>,
        expect_summary: bool,
    }

    let cases = vec![
        // env=true
        Case {
            env_val: Some("true"),
            flag: None,
            expect_summary: true,
        },
        Case {
            env_val: Some("true"),
            flag: Some("--summarize=true"),
            expect_summary: true,
        },
        Case {
            env_val: Some("true"),
            flag: Some("--summarize=false"),
            expect_summary: false,
        },
        Case {
            env_val: Some("true"),
            flag: Some("--summarize"),
            expect_summary: true,
        },
        // env=false
        Case {
            env_val: Some("false"),
            flag: None,
            expect_summary: false,
        },
        Case {
            env_val: Some("false"),
            flag: Some("--summarize=true"),
            expect_summary: true,
        },
        Case {
            env_val: Some("false"),
            flag: Some("--summarize=false"),
            expect_summary: false,
        },
        Case {
            env_val: Some("false"),
            flag: Some("--summarize"),
            expect_summary: true,
        },
        // env missing
        Case {
            env_val: None,
            flag: None,
            expect_summary: false,
        },
        Case {
            env_val: None,
            flag: Some("--summarize=true"),
            expect_summary: true,
        },
        Case {
            env_val: None,
            flag: Some("--summarize=false"),
            expect_summary: false,
        },
        Case {
            env_val: None,
            flag: Some("--summarize"),
            expect_summary: true,
        },
    ];

    for (i, case) in cases.iter().enumerate() {
        let _ = fs::remove_dir_all(tempdir.path().join(".turbo/runs"));

        let mut args = vec!["run", "build"];
        if let Some(flag) = case.flag {
            args.push(flag);
        }

        let env: Vec<(&str, &str)> = match case.env_val {
            Some(val) => vec![("TURBO_RUN_SUMMARY", val)],
            None => vec![],
        };

        run_turbo_with_env(tempdir.path(), &args, &env);

        let has_summary = tempdir.path().join(".turbo/runs").exists()
            && fs::read_dir(tempdir.path().join(".turbo/runs"))
                .map(|d| {
                    d.filter_map(|e| e.ok())
                        .any(|e| e.file_name().to_string_lossy().ends_with(".json"))
                })
                .unwrap_or(false);

        assert_eq!(
            has_summary, case.expect_summary,
            "case {i}: env={:?} flag={:?} expected summary={} got={}",
            case.env_val, case.flag, case.expect_summary, has_summary
        );
    }
}

fn task_definition(&self, task_id: &TaskId<'static>) -> Result<&TaskDefinition, Error> {
    self.engine
        .task_definition(task_id)
        .ok_or_else(|| Error::MissingTask(task_id.clone().into_owned()))
}

fn from_processed(
    processed: ProcessedTaskDefinition,
    path_to_repo_root: &RelativeUnixPath,
) -> Result<TaskDefinition, BuilderError> {
    // Convert outputs with turbo_root resolution
    let outputs = processed
        .outputs
        .map(|outputs| task_outputs_from_processed(outputs, path_to_repo_root))
        .transpose()?
        .unwrap_or_default();

    let cache = processed.cache.is_none_or(|c| c.into_inner());
    let interactive = processed
        .interactive
        .as_ref()
        .map(|value| value.value)
        .unwrap_or_default();

    if let Some(interactive) = &processed.interactive {
        let (span, text) = interactive.span_and_text("turbo.json");
        if cache && interactive.value {
            return Err(BuilderError::TurboJson(
                turborepo_turbo_json::Error::InteractiveNoCacheable { span, text },
            ));
        }
    }

    let persistent = *processed.persistent.unwrap_or_default();
    let interruptible = processed.interruptible.unwrap_or_default();
    if *interruptible && !persistent {
        let (span, text) = interruptible.span_and_text("turbo.json");
        return Err(BuilderError::TurboJson(
            turborepo_turbo_json::Error::InterruptibleButNotPersistent { span, text },
        ));
    }

    let mut topological_dependencies: Vec<Spanned<TaskName>> = Vec::new();
    let mut task_dependencies: Vec<Spanned<TaskName>> = Vec::new();
    if let Some(depends_on) = processed.depends_on {
        for dependency in depends_on.deps {
            let (dependency, depspan) = dependency.split();
            let dependency: String = dependency.into();
            if let Some(topo_dependency) =
                dependency.strip_prefix(TOPOLOGICAL_PIPELINE_DELIMITER)
            {
                topological_dependencies.push(depspan.to(topo_dependency.to_string().into()));
            } else {
                task_dependencies.push(depspan.to(dependency.into()));
            }
        }
    }

    task_dependencies.sort_by(|a, b| a.value.cmp(&b.value));
    topological_dependencies.sort_by(|a, b| a.value.cmp(&b.value));

    let env = processed.env.map(|env| env.vars).unwrap_or_default();

    // Convert inputs with turbo_root resolution
    let inputs = processed
        .inputs
        .map(|inputs| TaskInputs::from_processed(inputs, path_to_repo_root))
        .unwrap_or_default();

    let pass_through_env = processed.pass_through_env.map(|env| env.vars);

    let with = processed.with.map(|with_tasks| with_tasks.tasks);

    Ok(TaskDefinition {
        outputs,
        cache,
        topological_dependencies,
        task_dependencies,
        env,
        inputs,
        pass_through_env,
        output_logs: *processed.output_logs.unwrap_or_default(),
        persistent,
        interruptible: *interruptible,
        interactive,
        env_mode: processed.env_mode.map(|mode| *mode.as_inner()),
        with,
    })
}

fn run_correct_turbo<R, C, S, V>(
    runtime: &ShimRuntime<R, C, S, V>,
    repo_state: RepoState,
    shim_args: ShimArgs,
    ui: ColorConfig,
) -> ShimResult<R::Error>
where
    R: TurboRunner,
    C: ConfigProvider,
    S: ChildSpawner,
    V: VersionProvider,
{
    let package_manager = repo_state.package_manager.as_ref();

    if let Some(turbo_state) = LocalTurboState::infer(&repo_state.root) {
        let config = runtime
            .config_provider
            .get_config(&repo_state.root, shim_args.root_turbo_json.as_ref());

        try_check_for_updates(&shim_args, turbo_state.version(), &config, package_manager);

        if turbo_state.local_is_self() {
            unsafe {
                env::set_var(INVOCATION_DIR_ENV_VAR, shim_args.invocation_dir.as_path());
            }
            debug!("Currently running turbo is local turbo.");
            run_cli(runtime, Some(repo_state), ui)
        } else {
            spawn_local_turbo(runtime, &repo_state, turbo_state, shim_args)
        }
    } else if let Some(local_config) = LocalTurboConfig::infer(&repo_state) {
        debug!(
            "Found configuration for turbo version {}",
            local_config.turbo_version()
        );
        spawn_npx_turbo(
            runtime,
            &repo_state,
            local_config.turbo_version(),
            shim_args,
        )
    } else {
        let version = runtime.version_provider.get_version();
        let config = runtime
            .config_provider
            .get_config(&repo_state.root, shim_args.root_turbo_json.as_ref());
        try_check_for_updates(&shim_args, version, &config, package_manager);

        // cli::run checks for this env var, rather than an arg, so that we can support
        // calling old versions without passing unknown flags.
        unsafe {
            env::set_var(INVOCATION_DIR_ENV_VAR, shim_args.invocation_dir.as_path());
        }
        debug!("Running command as global turbo");

        let should_warn_on_global = env::var(TURBO_GLOBAL_WARNING_DISABLED)
            .map_or(true, |disable| !matches!(disable.as_str(), "1" | "true"));

        let declared_version = repo_state
            .root_package_json
            .dependencies
            .as_ref()
            .and_then(|deps| deps.get("turbo"))
            .or_else(|| {
                repo_state
                    .root_package_json
                    .dev_dependencies
                    .as_ref()
                    .and_then(|deps| deps.get("turbo"))
            });

        if should_warn_on_global {
            let message = if let Some(declared_version) = declared_version {
                format!(
                    "No locally installed `turbo` found in your repository. Using globally \
                     installed version ({version}), which can cause unexpected \
                     behavior.\n\nInstalling the version in your repository ({declared_version}) \
                     before calling `turbo` will result in more predictable behavior across \
                     environments."
                )
            } else {
                format!(
                    "No locally installed `turbo` found in your repository. Using globally \
                     installed version ({version}). Using a specified version in your repository \
                     will result in more predictable behavior."
                )
            };
            debug!(%message, "global turbo warning");
            unsafe {
                env::set_var(GLOBAL_WARNING_ENV_VAR, &message);
            }
        }
        run_cli(runtime, Some(repo_state), ui)
    }
}

pub fn run<R, C, S, V>(runtime: &ShimRuntime<R, C, S, V>) -> ShimResult<R::Error>
where
    R: TurboRunner,
    C: ConfigProvider,
    S: ChildSpawner,
    V: VersionProvider,
{
    normalize_config_dir_env_vars();
    let args = match ShimArgs::parse() {
        Ok(args) => args,
        Err(e) => return ShimResult::ShimError(e.into()),
    };
    run_with_args(runtime, args)
}

fn run_cli<R, C, S, V>(
    runtime: &ShimRuntime<R, C, S, V>,
    repo_state: Option<RepoState>,
    ui: ColorConfig,
) -> ShimResult<R::Error>
where
    R: TurboRunner,
    C: ConfigProvider,
    S: ChildSpawner,
    V: VersionProvider,
{
    match runtime.runner.run(repo_state, ui) {
        Ok(code) => ShimResult::Ok(code),
        Err(e) => ShimResult::CliError(e),
    }
}

